#define BLOCK_SIZE 16

#define MAX_PD	(3.0e6)
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP	0.5

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;
const float amb_temp = 80.0f;

__kernel void hotspot(
    int num_iterations,
    __global const float *power,
    __global const float *temp_in,
    __global float *temp_out,
    int col,
    int row,
    int borderCols,
    int borderRows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    int blockCol = get_block_id(0);
    int blockRow = get_block_id(1);
    int localCol = get_local_id(0);
    int localRow = get_local_id(1);

    int c_start = blockCol * BLOCK_SIZE;
    int r_start = blockRow * BLOCK_SIZE;

    int c = c_start + localCol;
    int r = r_start + localRow;

    if (r >= row || c >= col) return;

    float Cap_1 = step / Cap;
    float Rx_1 = 1.0f / Rx;
    float Ry_1 = 1.0f / Ry;
    float Rz_1 = 1.0f / Rz;

    float delta = 0.0f;
    float current_temp = temp_in[r * col + c];
    float current_power = power[r * col + c];

    bool is_top = (r == 0);
    bool is_bottom = (r == row - 1);
    bool is_left = (c == 0);
    bool is_right = (c == col - 1);

    if (is_top && is_left) {
        // Corner (0,0)
        delta = Cap_1 * (current_power +
            (temp_in[1 * col + 0] - current_temp) * Rx_1 +
            (temp_in[0 * col + 1] - current_temp) * Ry_1 +
            (amb_temp - current_temp) * Rz_1);
    }
    else if (is_top && is_right) {
        // Corner (0, col-1)
        delta = Cap_1 * (current_power +
            (temp_in[0 * col + c - 1] - current_temp) * Rx_1 +
            (temp_in[1 * col + c] - current_temp) * Ry_1 +
            (amb_temp - current_temp) * Rz_1);
    }
    else if (is_bottom && is_right) {
        // Corner (row-1, col-1)
        delta = Cap_1 * (current_power +
            (temp_in[r * col + c - 1] - current_temp) * Rx_1 +
            (temp_in[(r - 1) * col + c] - current_temp) * Ry_1 +
            (amb_temp - current_temp) * Rz_1);
    }
    else if (is_bottom && is_left) {
        // Corner (row-1, 0)
        delta = Cap_1 * (current_power +
            (temp_in[r * col + 1] - current_temp) * Rx_1 +
            (temp_in[(r - 1) * col + 0] - current_temp) * Ry_1 +
            (amb_temp - current_temp) * Rz_1);
    }
    else if (is_top) {
        // Top edge (not corner)
        delta = Cap_1 * (current_power +
            (temp_in[0 * col + c + 1] + temp_in[0 * col + c - 1] - 2.0f * current_temp) * Rx_1 +
            (temp_in[1 * col + c] - current_temp) * Ry_1 +
            (amb_temp - current_temp) * Rz_1);
    }
    else if (is_right) {
        // Right edge (not corner)
        delta = Cap_1 * (current_power +
            (temp_in[(r + 1) * col + c] + temp_in[(r - 1) * col + c] - 2.0f * current_temp) * Ry_1 +
            (temp_in[r * col + c - 1] - current_temp) * Rx_1 +
            (amb_temp - current_temp) * Rz_1);
    }
    else if (is_bottom) {
        // Bottom edge (not corner)
        delta = Cap_1 * (current_power +
            (temp_in[r * col + c + 1] + temp_in[r * col + c - 1] - 2.0f * current_temp) * Rx_1 +
            (temp_in[(r - 1) * col + c] - current_temp) * Ry_1 +
            (amb_temp - current_temp) * Rz_1);
    }
    else if (is_left) {
        // Left edge (not corner)
        delta = Cap_1 * (current_power +
            (temp_in[(r + 1) * col + 0] + temp_in[(r - 1) * col + 0] - 2.0f * current_temp) * Ry_1 +
            (temp_in[r * col + 1] - current_temp) * Rx_1 +
            (amb_temp - current_temp) * Rz_1);
    }
    else {
        // Interior
        delta = Cap_1 * (current_power +
            (temp_in[(r + 1) * col + c] + temp_in[(r - 1) * col + c] - 2.0f * current_temp) * Ry_1 +
            (temp_in[r * col + c + 1] + temp_in[r * col + c - 1] - 2.0f * current_temp) * Rx_1 +
            (amb_temp - current_temp) * Rz_1);
    }

    temp_out[r * col + c] = current_temp + delta;
}
